163	    return {
164	      type: 'switch',
165	      onClick: () => setType(type === 'allConnections' ? 'flowLog' : 'allConnections'),
166	      isDelete: type !== 'allConnections'
167	    };
168	  }, [canSwitchTypes, setType, type]);
169	
170	  const getDirIntsFilter = React.useCallback((): RecordFieldFilter | undefined => {
171	    //get interface filter and values
172	    const interfaceCol = columns.find(c => c.id === ColumnsId.interfaces);
173	    if (!interfaceCol) {
174	      console.error("getDirIntsFilter can't find interfaceCol");
175	      return undefined;
176	    }
177	    const interfaceFilterKey = {
178	      def: findFilter(filterDefinitions, interfaceCol!.quickFilter!)!,
179	      compare: FilterCompare.equal
180	    };
181	    const interfaceFilterValues = _.uniq(record.fields.Interfaces)!.map(v => ({ v, display: v }));
182	    const isDeleteInterface = doesIncludeFilter(filters, interfaceFilterKey, interfaceFilterValues);
183	
184	    //get direction filter and values
185	    const directionCol = columns.find(c => c.id === ColumnsId.ifdirs);
186	    if (!directionCol) {
187	      console.error("getDirIntsFilter can't find directionCol");
188	      return undefined;
189	    }
190	    const directionFilterKey = {
191	      def: findFilter(filterDefinitions, directionCol!.quickFilter!)!,
192	      compare: FilterCompare.equal
193	    };
194	    const directionFilterValues = _.uniq(record.fields.IfDirections)!.map(v => ({
195	      v: String(v),
196	      display: getDirectionDisplayString(String(v) as FlowDirection, t)
197	    }));
198	    const isDeleteDirection = doesIncludeFilter(filters, directionFilterKey, directionFilterValues);
199	
200	    //final state is composition of both interfaces and directions
201	    const isDelete = isDeleteInterface && isDeleteDirection;
202	    return {
203	      type: 'filter',
204	      onClick: () => {
205	        let newFilters = _.cloneDeep(filters);
206	        if (isDelete) {
207	          newFilters = removeFromFilters(newFilters, interfaceFilterKey);
208	          newFilters = removeFromFilters(newFilters, directionFilterKey);
209	          setFilters(newFilters);
210	        } else {
211	          const foundInterfaceFilter = findFromFilters(newFilters, interfaceFilterKey);
212	          if (foundInterfaceFilter) {
213	            foundInterfaceFilter.values = interfaceFilterValues;
214	          } else {
215	            newFilters.push({
216	              def: interfaceFilterKey.def,
217	              compare: FilterCompare.equal,
218	              values: interfaceFilterValues
219	            });
220	          }
221	          const foundDirectionFilter = findFromFilters(newFilters, directionFilterKey);
222	          if (foundDirectionFilter) {
223	            foundDirectionFilter.values = directionFilterValues;
224	          } else {
225	            newFilters.push({
226	              def: directionFilterKey.def,
227	              compare: FilterCompare.equal,
228	              values: directionFilterValues
229	            });
230	          }
231	          setFilters(newFilters);
232	        }
233	      },
234	      isDelete
235	    };
236	  }, [columns, filterDefinitions, filters, record.fields.IfDirections, record.fields.Interfaces, setFilters, t]);
237	
238	  const getGenericAnyOfFilter = React.useCallback(
239	    (col: Column, values: string[]): RecordFieldFilter | undefined => {
240	      const def = col.quickFilter ? findFilter(filterDefinitions, col.quickFilter) : undefined;
241	      if (!def) {
242	        return undefined;
243	      }
244	      const filterKey = { def: def, compare: FilterCompare.equal };
245	      const filterValues: FilterValue[] = values.map(v => ({ v: v }));
246	      const isDelete = doesIncludeFilter(filters, filterKey, filterValues);
247	      return {
248	        type: 'filter',
249	        onClick: () => {
250	          if (isDelete) {
251	            setFilters(removeFromFilters(filters, filterKey));
252	          } else {
253	            const newFilters = _.cloneDeep(filters);
254	            const found = findFromFilters(newFilters, filterKey);
255	            if (found) {
256	              found.values = filterValues;
257	            } else {
258	              newFilters.push({ def: def, compare: FilterCompare.equal, values: filterValues });
259	            }
260	            setFilters(newFilters);
261	          }
262	        },
263	        isDelete: isDelete
264	      };
265	    },
266	    [filterDefinitions, filters, setFilters]
267	  );
268	
269	  const getGenericFilter = React.useCallback(
270	    (col: Column, value: unknown): RecordFieldFilter | undefined => {
271	      const def = col.quickFilter ? findFilter(filterDefinitions, col.quickFilter) : undefined;
272	      if (!def) {
273	        return undefined;
274	      }
275	      const filterKey = { def: def, compare: FilterCompare.equal };
276	      const valueStr = String(value);
277	      const isDelete = doesIncludeFilter(filters, filterKey, [{ v: valueStr }]);
278	      return {
279	        type: 'filter',
280	        onClick: async () => {
281	          if (isDelete) {
282	            setFilters(removeFromFilters(filters, filterKey));
283	          } else {
284	            const values = [
285	              {
286	                v: Array.isArray(value) ? value.join(value.length == 2 ? '.' : ':') : valueStr,
287	                display: (await def.autocomplete(valueStr)).find(o => o.value === valueStr)?.name
288	              }
289	            ];
290	            // TODO: is it relevant to show composed columns?
291	            const newFilters = _.cloneDeep(filters);
292	            const found = findFromFilters(newFilters, filterKey);
293	            if (found) {
294	              found.values = values;
295	            } else {
296	              newFilters.push({ def: def, compare: FilterCompare.equal, values: values });
297	            }
298	            setFilters(newFilters);
299	          }
300	        },
301	        isDelete: isDelete
302	      };
303	    },
304	    [filterDefinitions, filters, setFilters]
305	  );
306	
307	  const getPktDropFilter = React.useCallback(
308	    (col: Column, cause?: string): RecordFieldFilter | undefined => {
309	      if (!allowPktDrops || !cause) {
310	        return undefined;
311	      }
312	      return getGenericFilter(col, cause);
313	    },
314	    [allowPktDrops, getGenericFilter]
315	  );
316	
317	  const getGroup = React.useCallback(
318	    (g: ColumnGroup, i: number, content: React.ReactElement) => {
319	      const toggleId = `toggle-${i}`;
320	      const key = `group-${i}`;
321	      return g.title ? (
322	        <div className="record-group-container" key={key} data-test-id={key}>
323	          <Divider />
324	          <AccordionItem data-test-id={key}>
325	            <AccordionToggle
326	              className="borderless-accordion"
327	              onClick={() => toggle(toggleId)}
328	              id={toggleId}
329	
330	            >
331	              {g.title}
332	            </AccordionToggle>
333	            <AccordionContent
334	              className="borderless-accordion"
335	              id={toggleId + '-content'}
336	
337	            >
338	              {content}
339	            </AccordionContent>
340	          </AccordionItem>
341	        </div>
342	      ) : (
343	        <div className="record-group-container" key={key} data-test-id={key}>
344	          {content}
345	        </div>
346	      );
347	    },
348	    [hidden, toggle]
349	  );
350	
351	  const getTitle = React.useCallback(() => {
352	    switch (record.labels._RecordType) {
353	      case 'newConnection':
354	      case 'heartbeat':
355	      case 'endConnection':
356	        return t('Conversation event information');
357	      case 'flowLog':
358	      default:
359	        return t('Flow information');
360	    }
361	  }, [record.labels._RecordType, t]);
362	
363	  const getSortedJSON = React.useCallback(() => {
364	    const flat = { ...record.labels, ...record.fields };
365	    return JSON.stringify(flat, Object.keys(flat).sort(), 2);
366	  }, [record]);
367	
368	  const groups = getColumnGroups(
369	    getVisibleColumns().filter(
370	      c =>
371	        //remove empty / duplicates columns for Node
372	        (record?.labels.SrcK8S_Type !== 'Node' ||
373	          ![
374	            ColumnsId.srcnamespace,
375	            ColumnsId.srcowner,
376	            ColumnsId.srcownertype,
377	            ColumnsId.srchostaddr,
378	            ColumnsId.srchostname,
379	            ColumnsId.srczone
380	          ].includes(c.id)) &&
381	        (record?.labels.DstK8S_Type !== 'Node' ||
382	          ![
383	            ColumnsId.dstnamespace,
384	            ColumnsId.dstowner,
385	            ColumnsId.dstownertype,
386	            ColumnsId.dsthostaddr,
387	            ColumnsId.dsthostname,
388	            ColumnsId.dstzone
389	          ].includes(c.id))
390	    )
391	  );
392	
393	  const isPartialFlow = !record.fields.Bytes && !record.fields.Packets;
394	
395	  return (
396	    <DrawerPanelContent
397	      data-test-id={id}
398	      id={id}
399	      className="drawer-panel-content"
400	      isResizable
401	      defaultSize={defaultSize}
402	      minSize={minSize}
403	      maxSize={maxSize}
404	    >
405	      <DrawerHead id={`${id}-drawer-head`} data-test-id="drawer-head" className="drawer-head">
406	        <Text data-test-id="drawer-head-text" component={TextVariants.h2}>
407	          {getTitle()}
408	        </Text>
409	        <DrawerActions>
410	          <DrawerCloseButton data-test-id="drawer-close-button" className="drawer-close-button" onClick={onClose} />
411	        </DrawerActions>
412	      </DrawerHead>
413	      <Divider />
414	      <DrawerPanelBody id={`${id}-drawer-body`} className="drawer-body" data-test-id="drawer-body">
415	        <Tabs
416	          id="drawer-tabs"
417	          activeKey={activeTab}
418	          usePageInsets
419	          onSelect={(e, key) => setActiveTab(key as string)}
420	          role="region"
421	        >
422	          <Tab className="drawer-tab" eventKey={'details'} title={<TabTitleText>{t('Details')}</TabTitleText>}>
423	            {isPartialFlow && (
424	              <Text id="partial-flow-text" component={TextVariants.p}>
425	                <InfoCircleIcon className="record-panel-warning" />
426	                {t(
427	                  // eslint-disable-next-line max-len
428	                  'This is a partial flow: it contains only enrichment data and is missing some basic information such as byte and packet counters, TCP flags or MAC addresses. This information can likely be found in adjacent flows.'
429	                )}
430	              </Text>
431	            )}
432	            <Accordion asDefinitionList={false}>
433	              {groups.map((g, i) =>
434	                getGroup(
435	                  g,
436	                  i,
437	                  <div className="record-group-container">
438	                    {g.columns.map(c => (
439	                      <TextContent
440	                        className={`record-field-container ${g.title ? 'grouped' : ''}`}
441	                        key={c.id}
442	                        data-test-id={`drawer-field-${c.id}`}
443	                      >
444	                        {c.tooltip ? (
445	                          <Popover
446	                            headerContent={c.name}
447	                            bodyContent={<div className="record-field-popover-body">{c.tooltip}</div>}
448	                            footerContent={
449	                              c.docURL ? (
450	                                <div className="record-field-popover-footer">
451	                                  {`${t('More info')}: `}
452	                                  <a href={c.docURL} target="_blank" rel="noopener noreferrer">
453	                                    {c.docURL}
454	                                  </a>
455	                                </div>
456	                              ) : undefined
457	                            }
458	                          >
459	                            <Button
460	                              icon={<Text component={TextVariants.h4}>{getShortColumnName(c)}</Text>}
461	                              variant="plain"
462	                              className="record-field-title-popover-button"
463	                            />
464	                          </Popover>
465	                        ) : (
466	                          <Text component={TextVariants.h4} className="record-field-title">
467	                            {c.name}
468	                          </Text>
469	                        )}
470	                        <RecordField
471	                          allowPktDrops={allowPktDrops}
472	                          flow={record}
473	                          column={c}
474	                          filter={getFilter(c)}
475	                          size={'s'}
476	                          useLinks={true}
477	                          detailed={true}
478	                          isDark={isDark}
479	                        />
480	                      </TextContent>
481	                    ))}
482	                  </div>
483	                )
484	              )}
485	            </Accordion>
486	          </Tab>
487	          <Tab className="drawer-tab" eventKey={'raw'} title={<TabTitleText>{t('Raw')}</TabTitleText>}>
488	            <ClipboardCopy
489	              data-test-id="drawer-json-copy"
490	              isCode
491	              isReadOnly
492	              isExpanded
493	              hoverTip={t('Copy')}
494	              clickTip={t('Copied')}
495	              variant={ClipboardCopyVariant.expansion}
496	            >
497	              {getSortedJSON()}
498	            </ClipboardCopy>
499	          </Tab>
500	        </Tabs>
501	      </DrawerPanelBody>
502	    </DrawerPanelContent>
503	  );
504	};
505	
506	export default RecordPanel;

