205	        let newFilters = _.cloneDeep(filters);
206	        if (isDelete) {
207	          newFilters = removeFromFilters(newFilters, interfaceFilterKey);
208	          newFilters = removeFromFilters(newFilters, directionFilterKey);
209	          setFilters(newFilters);
210	        } else {
211	          const foundInterfaceFilter = findFromFilters(newFilters, interfaceFilterKey);
212	          if (foundInterfaceFilter) {
213	            foundInterfaceFilter.values = interfaceFilterValues;
214	          } else {
215	            newFilters.push({
216	              def: interfaceFilterKey.def,
217	              compare: FilterCompare.equal,
218	              values: interfaceFilterValues
219	            });
220	          }
221	          const foundDirectionFilter = findFromFilters(newFilters, directionFilterKey);
222	          if (foundDirectionFilter) {
223	            foundDirectionFilter.values = directionFilterValues;
224	          } else {
225	            newFilters.push({
226	              def: directionFilterKey.def,
227	              compare: FilterCompare.equal,
228	              values: directionFilterValues
229	            });
230	          }
231	          setFilters(newFilters);
232	        }
233	      },
234	      isDelete
235	    };
236	  }, [columns, filterDefinitions, filters, record.fields.IfDirections, record.fields.Interfaces, setFilters, t]);
237	
238	  const getGenericAnyOfFilter = React.useCallback(
239	    (col: Column, values: string[]): RecordFieldFilter | undefined => {
240	      const def = col.quickFilter ? findFilter(filterDefinitions, col.quickFilter) : undefined;
241	      if (!def) {
242	        return undefined;
243	      }
244	      const filterKey = { def: def, compare: FilterCompare.equal };
245	      const filterValues: FilterValue[] = values.map(v => ({ v: v }));
246	      const isDelete = doesIncludeFilter(filters, filterKey, filterValues);
247	      return {
248	        type: 'filter',
249	        onClick: () => {
250	          if (isDelete) {
251	            setFilters(removeFromFilters(filters, filterKey));
252	          } else {
253	            const newFilters = _.cloneDeep(filters);
254	            const found = findFromFilters(newFilters, filterKey);
255	            if (found) {
256	              found.values = filterValues;
257	            } else {
258	              newFilters.push({ def: def, compare: FilterCompare.equal, values: filterValues });
259	            }
260	            setFilters(newFilters);
261	          }
262	        },
263	        isDelete: isDelete
264	      };
265	    },
266	    [filterDefinitions, filters, setFilters]
267	  );
268	
269	  const getGenericFilter = React.useCallback(
270	    (col: Column, value: unknown): RecordFieldFilter | undefined => {
271	      const def = col.quickFilter ? findFilter(filterDefinitions, col.quickFilter) : undefined;
272	      if (!def) {
273	        return undefined;
274	      }
275	      const filterKey = { def: def, compare: FilterCompare.equal };
276	      const valueStr = String(value);
277	      const isDelete = doesIncludeFilter(filters, filterKey, [{ v: valueStr }]);
278	      return {
279	        type: 'filter',
280	        onClick: async () => {
281	          if (isDelete) {
282	            setFilters(removeFromFilters(filters, filterKey));
283	          } else {
284	            const values = [
285	              {
286	                v: Array.isArray(value) ? value.join(value.length == 2 ? '.' : ':') : valueStr,
287	                display: (await def.autocomplete(valueStr)).find(o => o.value === valueStr)?.name
288	              }
289	            ];
290	            // TODO: is it relevant to show composed columns?
291	            const newFilters = _.cloneDeep(filters);
292	            const found = findFromFilters(newFilters, filterKey);
293	            if (found) {
294	              found.values = values;
295	            } else {
296	              newFilters.push({ def: def, compare: FilterCompare.equal, values: values });
297	            }
298	            setFilters(newFilters);
299	          }
300	        },
301	        isDelete: isDelete
302	      };
303	    },
304	    [filterDefinitions, filters, setFilters]
305	  );
306	
307	  const getPktDropFilter = React.useCallback(
308	    (col: Column, cause?: string): RecordFieldFilter | undefined => {
309	      if (!allowPktDrops || !cause) {
310	        return undefined;
311	      }
312	      return getGenericFilter(col, cause);
313	    },
314	    [allowPktDrops, getGenericFilter]
315	  );
316	
317	  const getGroup = React.useCallback(
318	    (g: ColumnGroup, i: number, content: React.ReactElement) => {
319	      const toggleId = `toggle-${i}`;
320	      const key = `group-${i}`;
321	      return g.title ? (
322	        <div className="record-group-container" key={key} data-test-id={key}>
323	          <Divider />
324	          <AccordionItem data-test-id={key} isExpanded={!hidden.includes(toggleId)}>
325	            <AccordionToggle
326	              className="borderless-accordion"
327	              onClick={() => toggle(toggleId)}
328	              id={toggleId}
329	            >
330	              {g.title}
331	            </AccordionToggle>
332	            <AccordionContent
333	              className="borderless-accordion"
334	              id={toggleId + '-content'}
335	            >
336	              {content}
337	            </AccordionContent>
338	          </AccordionItem>
339	        </div>
340	      ) : (
341	        <div className="record-group-container" key={key} data-test-id={key}>
342	          {content}
343	        </div>
344	      );
345	    },
346	    [hidden, toggle]
347	  );
348	
349	  const getTitle = React.useCallback(() => {
350	    switch (record.labels._RecordType) {
351	      case 'newConnection':
352	      case 'heartbeat':
353	      case 'endConnection':
354	        return t('Conversation event information');
355	      case 'flowLog':
356	      default:
357	        return t('Flow information');
358	    }
359	  }, [record.labels._RecordType, t]);
360	
361	  const getSortedJSON = React.useCallback(() => {
362	    const flat = { ...record.labels, ...record.fields };
363	    return JSON.stringify(flat, Object.keys(flat).sort(), 2);
364	  }, [record]);
365	
366	  const groups = getColumnGroups(
367	    getVisibleColumns().filter(
368	      c =>
369	        //remove empty / duplicates columns for Node
370	        (record?.labels.SrcK8S_Type !== 'Node' ||
371	          ![
372	            ColumnsId.srcnamespace,
373	            ColumnsId.srcowner,
374	            ColumnsId.srcownertype,
375	            ColumnsId.srchostaddr,
376	            ColumnsId.srchostname,
377	            ColumnsId.srczone
378	          ].includes(c.id)) &&
379	        (record?.labels.DstK8S_Type !== 'Node' ||
380	          ![
381	            ColumnsId.dstnamespace,
382	            ColumnsId.dstowner,
383	            ColumnsId.dstownertype,
384	            ColumnsId.dsthostaddr,
385	            ColumnsId.dsthostname,
386	            ColumnsId.dstzone
387	          ].includes(c.id))
388	    )
389	  );
390	
391	  const isPartialFlow = !record.fields.Bytes && !record.fields.Packets;
392	
393	  return (
394	    <DrawerPanelContent
395	      data-test-id={id}
396	      id={id}
397	      className="drawer-panel-content"
398	      isResizable
399	      defaultSize={defaultSize}
400	      minSize={minSize}
401	      maxSize={maxSize}
402	    >
403	      <DrawerHead id={`${id}-drawer-head`} data-test-id="drawer-head" className="drawer-head">
404	        <Text data-test-id="drawer-head-text" component={TextVariants.h2}>
405	          {getTitle()}
406	        </Text>
407	        <DrawerActions>
408	          <DrawerCloseButton data-test-id="drawer-close-button" className="drawer-close-button" onClick={onClose} />
409	        </DrawerActions>
410	      </DrawerHead>
411	      <Divider />
412	      <DrawerPanelBody id={`${id}-drawer-body`} className="drawer-body" data-test-id="drawer-body">
413	        <Tabs
414	          id="drawer-tabs"
415	          activeKey={activeTab}
416	          usePageInsets
417	          onSelect={(e, key) => setActiveTab(key as string)}
418	          role="region"
419	        >
420	          <Tab className="drawer-tab" eventKey={'details'} title={<TabTitleText>{t('Details')}</TabTitleText>}>
421	            {isPartialFlow && (
422	              <Text id="partial-flow-text" component={TextVariants.p}>
423	                <InfoCircleIcon className="record-panel-warning" />
424	                {t(
425	                  // eslint-disable-next-line max-len
426	                  'This is a partial flow: it contains only enrichment data and is missing some basic information such as byte and packet counters, TCP flags or MAC addresses. This information can likely be found in adjacent flows.'
427	                )}
428	              </Text>
429	            )}
430	            <Accordion asDefinitionList={false}>
431	              {groups.map((g, i) =>
432	                getGroup(
433	                  g,
434	                  i,
435	                  <div className="record-group-container">
436	                    {g.columns.map(c => (
437	                      <TextContent
438	                        className={`record-field-container ${g.title ? 'grouped' : ''}`}
439	                        key={c.id}
440	                        data-test-id={`drawer-field-${c.id}`}
441	                      >
442	                        {c.tooltip ? (
443	                          <Popover
444	                            headerContent={c.name}
445	                            bodyContent={<div className="record-field-popover-body">{c.tooltip}</div>}
446	                            footerContent={
447	                              c.docURL ? (
448	                                <div className="record-field-popover-footer">
449	                                  {`${t('More info')}: `}
450	                                  <a href={c.docURL} target="_blank" rel="noopener noreferrer">
451	                                    {c.docURL}
452	                                  </a>
453	                                </div>
454	                              ) : undefined
455	                            }
456	                          >
457	                            <Button
458	                              icon={<Text component={TextVariants.h4}>{getShortColumnName(c)}</Text>}
459	                              variant="plain"
460	                              className="record-field-title-popover-button"
461	                            />
462	                          </Popover>
463	                        ) : (
464	                          <Text component={TextVariants.h4} className="record-field-title">
465	                            {c.name}
466	                          </Text>
467	                        )}
468	                        <RecordField
469	                          allowPktDrops={allowPktDrops}
470	                          flow={record}
471	                          column={c}
472	                          filter={getFilter(c)}
473	                          size={'s'}
474	                          useLinks={true}
475	                          detailed={true}
476	                          isDark={isDark}
477	                        />
478	                      </TextContent>
479	                    ))}
480	                  </div>
481	                )
482	              )}
483	            </Accordion>
484	          </Tab>
485	          <Tab className="drawer-tab" eventKey={'raw'} title={<TabTitleText>{t('Raw')}</TabTitleText>}>
486	            <ClipboardCopy
487	              data-test-id="drawer-json-copy"
488	              isCode
489	              isReadOnly
490	              isExpanded
491	              hoverTip={t('Copy')}
492	              clickTip={t('Copied')}
493	              variant={ClipboardCopyVariant.expansion}
494	            >
495	              {getSortedJSON()}
496	            </ClipboardCopy>
497	          </Tab>
498	        </Tabs>
499	      </DrawerPanelBody>
500	    </DrawerPanelContent>
501	  );
502	};
503	
504	export default RecordPanel;

