  1	import {
  2	  Accordion,
  3	  AccordionContent,
  4	  AccordionItem,
  5	  AccordionToggle,
  6	  Button,
  7	  ClipboardCopy,
  8	  ClipboardCopyVariant,
  9	  Divider,
 10	  DrawerActions,
 11	  DrawerCloseButton,
 12	  DrawerHead,
 13	  DrawerPanelBody,
 14	  DrawerPanelContent,
 15	  Popover,
 16	  Tab,
 17	  Tabs,
 18	  TabTitleText,
 19	  Content,
 20	  ContentVariants
 21	} from '@patternfly/react-core';
 22	import { InfoCircleIcon } from '@patternfly/react-icons';
 23	import _ from 'lodash';
 24	import * as React from 'react';
 25	import { useTranslation } from 'react-i18next';
 26	import { FlowDirection, getDirectionDisplayString, Record } from '../../../api/ipfix';
 27	import {
 28	  doesIncludeFilter,
 29	  Filter,
 30	  FilterCompare,
 31	  FilterDefinition,
 32	  FilterValue,
 33	  findFromFilters,
 34	  removeFromFilters
 35	} from '../../../model/filters';
 36	import { RecordType } from '../../../model/flow-query';
 37	import { Column, ColumnGroup, ColumnsId, getColumnGroups, getShortColumnName } from '../../../utils/columns';
 38	import { TimeRange } from '../../../utils/datetime';
 39	import { findFilter } from '../../../utils/filter-definitions';
 40	import { defaultSize, maxSize, minSize } from '../../../utils/panel';
 41	import { defaultTimeRange } from '../../../utils/router';
 42	import RecordField, { RecordFieldFilter } from './record-field';
 43	import './record-panel.css';
 44	
 45	export type RecordDrawerProps = {
 46	  record: Record;
 47	  columns: Column[];
 48	  filters: Filter[];
 49	  filterDefinitions: FilterDefinition[];
 50	  range: number | TimeRange;
 51	  type: RecordType;
 52	  canSwitchTypes: boolean;
 53	  allowPktDrops: boolean;
 54	  isDark?: boolean;
 55	  setFilters: (v: Filter[]) => void;
 56	  setRange: (r: number | TimeRange) => void;
 57	  setType: (r: RecordType) => void;
 58	  onClose: () => void;
 59	  id?: string;
 60	};
 61	
 62	export const RecordPanel: React.FC<RecordDrawerProps> = ({
 63	  id,
 64	  record,
 65	  columns,
 66	  filters,
 67	  filterDefinitions,
 68	  range,
 69	  type,
 70	  canSwitchTypes,
 71	  allowPktDrops,
 72	  isDark,
 73	  setFilters,
 74	  setRange,
 75	  setType,
 76	  onClose
 77	}) => {
 78	  const { t } = useTranslation('plugin__netobserv-plugin');
 79	  const [hidden, setHidden] = React.useState<string[]>([]);
 80	  const [activeTab, setActiveTab] = React.useState<string>('details');
 81	
 82	  // hide empty columns
 83	  const getVisibleColumns = React.useCallback(() => {
 84	    const forbiddenColumns = [
 85	      ColumnsId.ifdirs,
 86	      ColumnsId.interfaces,
 87	      ColumnsId.dropbytes,
 88	      ColumnsId.droppackets,
 89	      ColumnsId.dropstate,
 90	      ColumnsId.dropcause,
 91	      ColumnsId.dropflags
 92	    ];
 93	    return columns.filter((c: Column) => {
 94	      if (!c.fieldValue) {
 95	        return false;
 96	      }
 97	      const value = c.fieldValue(record);
 98	      return !forbiddenColumns.includes(c.id) && value !== '' && !Number.isNaN(value);
 99	    });
100	  }, [columns, record]);
101	
102	  const toggle = React.useCallback(
103	    (id: string) => {
104	      const index = hidden.indexOf(id);
105	      const newExpanded: string[] =
106	        index >= 0 ? [...hidden.slice(0, index), ...hidden.slice(index + 1, hidden.length)] : [...hidden, id];
107	      setHidden(newExpanded);
108	    },
109	    [hidden]
110	  );
111	
112	  const getFilter = (col: Column) => {
113	    if (record && col.fieldValue) {
114	      const value = col.fieldValue(record);
115	      switch (col.id) {
116	        case ColumnsId.endtime:
117	          return getTimeRangeFilter(col, value);
118	        case ColumnsId.recordtype:
119	          return getRecordTypeFilter();
120	        case ColumnsId.packets:
121	          return getPktDropFilter(col, record.fields.PktDropLatestDropCause);
122	        case ColumnsId.icmptype:
123	          return getGenericFilter(col, (value as number[])[1]);
124	        case ColumnsId.icmpcode:
125	          return getGenericFilter(col, (value as number[])[2]);
126	        case ColumnsId.flowdirints:
127	          return getDirIntsFilter();
128	        case ColumnsId.tlstypes:
129	          return getGenericAnyOfFilter(col, value as string[]);
130	        default:
131	          return getGenericFilter(col, value);
132	      }
133	    }
134	    return undefined;
135	  };
136	
137	  const getTimeRangeFilter = React.useCallback(
138	    (col: Column, value: unknown): RecordFieldFilter => {
139	      const isDelete = typeof range !== 'number' && range.from === Number(value);
140	      return {
141	        type: 'filter',
142	        onClick: () => {
143	          if (isDelete) {
144	            setRange(defaultTimeRange);
145	          } else {
146	            //Filter at exact same date
147	            const dateSeconds = Math.floor(Number(value) / 1000);
148	            // Note: "to" field will be rounded up to the next second from the backend
149	            setRange({ from: dateSeconds, to: dateSeconds });
150	          }
151	        },
152	        isDelete: isDelete
153	      };
154	    },
155	    [range, setRange]
156	  );
157	
158	  const getRecordTypeFilter = React.useCallback((): RecordFieldFilter | undefined => {
159	    if (!canSwitchTypes) {
160	      return undefined;
161	    }
