306	  const getPktDropFilter = React.useCallback(
307	    (col: Column, cause?: string): RecordFieldFilter | undefined => {
308	      if (!allowPktDrops || !cause) {
309	        return undefined;
310	      }
311	      return getGenericFilter(col, cause);
312	    },
313	    [allowPktDrops, getGenericFilter]
314	  );
315	
316	  const getGroup = React.useCallback(
317	    (g: ColumnGroup, i: number, content: React.ReactElement) => {
318	      const toggleId = `toggle-${i}`;
319	      const key = `group-${i}`;
320	      return g.title ? (
321	        <div className="record-group-container" key={key} data-test-id={key}>
322	          <Divider />
323	          <AccordionItem data-test-id={key} isExpanded={!hidden.includes(toggleId)}>
324	            <AccordionToggle
325	              className="borderless-accordion"
326	              onClick={() => toggle(toggleId)}
327	              id={toggleId}
328	            >
329	              {g.title}
330	            </AccordionToggle>
331	            <AccordionContent
332	              className="borderless-accordion"
333	              id={toggleId + '-content'}
334	            >
335	              {content}
336	            </AccordionContent>
337	          </AccordionItem>
338	        </div>
339	      ) : (
340	        <div className="record-group-container" key={key} data-test-id={key}>
341	          {content}
342	        </div>
343	      );
344	    },
345	    [hidden, toggle]
346	  );
347	
348	  const getTitle = React.useCallback(() => {
349	    switch (record.labels._RecordType) {
350	      case 'newConnection':
351	      case 'heartbeat':
352	      case 'endConnection':
353	        return t('Conversation event information');
354	      case 'flowLog':
355	      default:
356	        return t('Flow information');
357	    }
358	  }, [record.labels._RecordType, t]);
359	
360	  const getSortedJSON = React.useCallback(() => {
361	    const flat = { ...record.labels, ...record.fields };
362	    return JSON.stringify(flat, Object.keys(flat).sort(), 2);
363	  }, [record]);
364	
365	  const groups = getColumnGroups(
366	    getVisibleColumns().filter(
367	      c =>
368	        //remove empty / duplicates columns for Node
369	        (record?.labels.SrcK8S_Type !== 'Node' ||
370	          ![
371	            ColumnsId.srcnamespace,
372	            ColumnsId.srcowner,
373	            ColumnsId.srcownertype,
374	            ColumnsId.srchostaddr,
375	            ColumnsId.srchostname,
376	            ColumnsId.srczone
377	          ].includes(c.id)) &&
378	        (record?.labels.DstK8S_Type !== 'Node' ||
379	          ![
380	            ColumnsId.dstnamespace,
381	            ColumnsId.dstowner,
382	            ColumnsId.dstownertype,
383	            ColumnsId.dsthostaddr,
384	            ColumnsId.dsthostname,
385	            ColumnsId.dstzone
386	          ].includes(c.id))
387	    )
388	  );
389	
390	  const isPartialFlow = !record.fields.Bytes && !record.fields.Packets;
391	
392	  return (
393	    <DrawerPanelContent
394	      data-test-id={id}
395	      id={id}
396	      className="drawer-panel-content"
397	      isResizable
398	      defaultSize={defaultSize}
399	      minSize={minSize}
400	      maxSize={maxSize}
401	    >
402	      <DrawerHead id={`${id}-drawer-head`} data-test-id="drawer-head" className="drawer-head">
403	        <Content data-test-id="drawer-head-text" component={ContentVariants.h2}>
404	          {getTitle()}
405	        </Content>
406	        <DrawerActions>
407	          <DrawerCloseButton data-test-id="drawer-close-button" className="drawer-close-button" onClick={onClose} />
408	        </DrawerActions>
409	      </DrawerHead>
410	      <Divider />
411	      <DrawerPanelBody id={`${id}-drawer-body`} className="drawer-body" data-test-id="drawer-body">
412	        <Tabs
413	          id="drawer-tabs"
414	          activeKey={activeTab}
415	          usePageInsets
416	          onSelect={(e, key) => setActiveTab(key as string)}
417	          role="region"
418	        >
419	          <Tab className="drawer-tab" eventKey={'details'} title={<TabTitleText>{t('Details')}</TabTitleText>}>
420	            {isPartialFlow && (
421	              <Content id="partial-flow-text" component={ContentVariants.p}>
422	                <InfoCircleIcon className="record-panel-warning" />
423	                {t(
424	                  // eslint-disable-next-line max-len
425	                  'This is a partial flow: it contains only enrichment data and is missing some basic information such as byte and packet counters, TCP flags or MAC addresses. This information can likely be found in adjacent flows.'
426	                )}
427	              </Content>
428	            )}
429	            <Accordion asDefinitionList={false}>
430	              {groups.map((g, i) =>
431	                getGroup(
432	                  g,
433	                  i,
434	                  <div className="record-group-container">
435	                    {g.columns.map(c => (
436	                      <Content
437	                        className={`record-field-container ${g.title ? 'grouped' : ''}`}
438	                        key={c.id}
439	                        data-test-id={`drawer-field-${c.id}`}
440	                      >
441	                        {c.tooltip ? (
442	                          <Popover
443	                            headerContent={c.name}
444	                            bodyContent={<div className="record-field-popover-body">{c.tooltip}</div>}
445	                            footerContent={
446	                              c.docURL ? (
447	                                <div className="record-field-popover-footer">
448	                                  {`${t('More info')}: `}
449	                                  <a href={c.docURL} target="_blank" rel="noopener noreferrer">
450	                                    {c.docURL}
451	                                  </a>
452	                                </div>
453	                              ) : undefined
454	                            }
455	                          >
456	                            <Button
457	                              icon={<Content component={ContentVariants.h4}>{getShortColumnName(c)}</Content>}
458	                              variant="plain"
459	                              className="record-field-title-popover-button"
460	                            />
461	                          </Popover>
462	                        ) : (
463	                          <Content component={ContentVariants.h4} className="record-field-title">
464	                            {c.name}
465	                          </Content>
466	                        )}
467	                        <RecordField
468	                          allowPktDrops={allowPktDrops}
469	                          flow={record}
470	                          column={c}
471	                          filter={getFilter(c)}
472	                          size={'s'}
473	                          useLinks={true}
474	                          detailed={true}
475	                          isDark={isDark}
476	                        />
477	                      </Content>
478	                    ))}
479	                  </div>
480	                )
481	              )}
482	            </Accordion>
483	          </Tab>
484	          <Tab className="drawer-tab" eventKey={'raw'} title={<TabTitleText>{t('Raw')}</TabTitleText>}>
485	            <ClipboardCopy
486	              data-test-id="drawer-json-copy"
487	              isCode
488	              isReadOnly
489	              isExpanded
490	              hoverTip={t('Copy')}
491	              clickTip={t('Copied')}
492	              variant={ClipboardCopyVariant.expansion}
493	            >
494	              {getSortedJSON()}
495	            </ClipboardCopy>
496	          </Tab>
497	        </Tabs>
498	      </DrawerPanelBody>
499	    </DrawerPanelContent>
500	  );
501	};
502	
503	export default RecordPanel;
